export const getCard = (cardId: string) => customerBackendAPI.getCard(cardId)
export const getCardDetails = (cardId: string) => customerBackendAPI.getCardDetails(cardId)
export const getGames = () => customerBackendAPI.getGames()
export const getSets = (gameCode?: string) => customerBackendAPI.getSets(gameCode)
export const getSearchSuggestions = (field: string, value: string, gameCode?: string) => 
  customerBackendAPI.getSearchSuggestions(field, value, gameCode)

// Inventory convenience exports
export const checkInventory = (variantId: string, options?: { useCache?: boolean; includeLocations?: boolean }) =>
  customerBackendAPI.checkInventory(variantId, options)

export const checkMultipleInventory = (variantIds: string[], options?: { useCache?: boolean; includeLocations?: boolean }) =>
  customerBackendAPI.checkMultipleInventory(variantIds, options)

export const invalidateInventoryCache = (variantIds: string[]) =>
  customerBackendAPI.invalidateInventoryCache(variantIds)

export const preWarmInventoryCache = (variantIds: string[]) =>
  customerBackendAPI.preWarmInventoryCache(variantIds)

// ── Deck API exports ───────────────────────────────────────────────────────────

export const getUserDecks = (): Promise<{ decks: DeckDto[] }> =>
  customerBackendAPI.get("/api/decks")

export const createDeck = (body: { gameId: string; formatCode: string; name: string }): Promise<any> =>
  customerBackendAPI.post("/api/decks", body)

export const patchDeck = (id: string, body: { name?: string; formatCode?: string }): Promise<any> =>
  customerBackendAPI.patch(`/api/decks/${id}`, body)

export const deleteDeck = (id: string): Promise<void> =>
  customerBackendAPI.delete(`/api/decks/${id}`)

export const duplicateDeck = (id: string): Promise<{ deck: DeckDto }> =>
  customerBackendAPI.post(`/api/decks/${id}/duplicate`, {})

export async function fetchGameListingCounts(): Promise<GameListingCounts | undefined> {
  try {
    const res = await fetch(`${CUSTOMER_BACKEND_URL}/api/catalog/listing-counts`, {
      next: { revalidate: 30 },
      signal: AbortSignal.timeout(5000),
    })
    if (!res.ok) return undefined
    return res.json()
  } catch {
    return undefined
  }
}

