import { render, screen } from "@testing-library/react"
import { TrendingStrip } from "../TrendingStrip"

const mockCards = [
  { id: "card-1", name: "Ragavan, Nimble Pilferer", set: "Modern Horizons 2", price: 58.99 },
  { id: "card-2", name: "Charizard ex", set: "Obsidian Flames", price: 42.5 },
]

describe("TrendingStrip", () => {
  it("returns null when cards is undefined", () => {
    const { container } = render(<TrendingStrip />)
    expect(container.innerHTML).toBe("")
  })

  it("returns null when cards is empty", () => {
    const { container } = render(<TrendingStrip cards={[]} />)
    expect(container.innerHTML).toBe("")
  })

  it("renders section with aria-label when cards are provided", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(
      screen.getByRole("region", { name: "Trending cards" })
    ).toBeInTheDocument()
  })

  it("renders section label 'Trending Now'", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(screen.getByText("Trending Now")).toBeInTheDocument()
  })

  it("renders card names", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(screen.getByText("Ragavan, Nimble Pilferer")).toBeInTheDocument()
    expect(screen.getByText("Charizard ex")).toBeInTheDocument()
  })

  it("renders card sets", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(screen.getByText("Modern Horizons 2")).toBeInTheDocument()
    expect(screen.getByText("Obsidian Flames")).toBeInTheDocument()
  })

  it("renders card prices formatted to 2 decimal places", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(screen.getByText("$58.99")).toBeInTheDocument()
    expect(screen.getByText("$42.50")).toBeInTheDocument()
  })

  it("links each card to /cards/:id", () => {
    render(<TrendingStrip cards={mockCards} />)
    const links = screen.getAllByRole("link")
    expect(links[0]).toHaveAttribute("href", "/cards/card-1")
    expect(links[1]).toHaveAttribute("href", "/cards/card-2")
  })
})

